// Termine normalisieren (egal welche Quelle)
const items = $input.all();
const now = new Date();
const results = [];

for (const item of items) {
  const data = item.json;

  // Termin-Daten extrahieren (flexibel für verschiedene Quellen)
  let terminDatum, schuelerName, schuelerTelefon, fahrlehrerName, terminArt;

  // Google Calendar Format
  if (data.start && data.start.dateTime) {
    terminDatum = new Date(data.start.dateTime);
    // Aus der Beschreibung oder dem Titel extrahieren
    const summary = data.summary || '';
    schuelerName = summary.split(' - ')[0] || 'Fahrschüler';
    schuelerTelefon = (data.description || '').match(/\+?\d[\d\s]{8,}/)?.[0] || '';
    fahrlehrerName = summary.split(' - ')[1] || '';
    terminArt = summary.split(' - ')[2] || 'Fahrstunde';
  }
  // Google Sheets Format
  else if (data.Datum || data.datum) {
    const datumStr = data.Datum || data.datum;
    const zeitStr = data.Uhrzeit || data.uhrzeit || data.Zeit || data.zeit || '09:00';
    terminDatum = new Date(`${datumStr}T${zeitStr}`);
    schuelerName = data.Schüler || data.schueler || data.Name || data.name || 'Fahrschüler';
    schuelerTelefon = data.Telefon || data.telefon || data.Handy || data.handy || data.WhatsApp || '';
    fahrlehrerName = data.Fahrlehrer || data.fahrlehrer || data.Lehrer || '';
    terminArt = data.Art || data.art || data.Typ || data.typ || 'Fahrstunde';
  }
  // API Format
  else if (data.appointment_date || data.termin_datum) {
    terminDatum = new Date(data.appointment_date || data.termin_datum);
    schuelerName = data.student_name || data.schueler_name || 'Fahrschüler';
    schuelerTelefon = data.student_phone || data.schueler_telefon || '';
    fahrlehrerName = data.instructor_name || data.fahrlehrer_name || '';
    terminArt = data.lesson_type || data.termin_art || 'Fahrstunde';
  }
  else {
    continue; // Unbekanntes Format, überspringen
  }

  if (!terminDatum || !schuelerTelefon) continue;

  // Telefonnummer bereinigen
  schuelerTelefon = schuelerTelefon.replace(/[\s\-\/]/g, '');
  if (!schuelerTelefon.startsWith('+')) {
    schuelerTelefon = '+49' + schuelerTelefon.replace(/^0/, '');
  }

  // Stunden bis zum Termin berechnen
  const stundenBisTermin = (terminDatum.getTime() - now.getTime()) / (1000 * 60 * 60);

  // Erinnerungstyp bestimmen
  let erinnerungsTyp = null;
  if (stundenBisTermin >= 23.5 && stundenBisTermin <= 24.5) {
    erinnerungsTyp = '24h';
  } else if (stundenBisTermin >= 1.5 && stundenBisTermin <= 2.5) {
    erinnerungsTyp = '2h';
  }

  if (!erinnerungsTyp) continue; // Kein Erinnerungsfenster

  // Datum und Uhrzeit formatieren
  const optionen = { weekday: 'long', day: 'numeric', month: 'long' };
  const terminDatumFormatiert = terminDatum.toLocaleDateString('de-DE', optionen);
  const terminZeitFormatiert = terminDatum.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });

  results.push({
    json: {
      schuelerName,
      schuelerTelefon,
      fahrlehrerName,
      terminArt,
      terminDatum: terminDatum.toISOString(),
      terminDatumFormatiert,
      terminZeitFormatiert,
      erinnerungsTyp,
      stundenBisTermin: Math.round(stundenBisTermin * 10) / 10
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true } }];

// Erinnerung loggen
const item = $input.first();
const logEntry = {
  timestamp: new Date().toISOString(),
  schueler: item.json.schuelerName,
  telefon: item.json.schuelerTelefon,
  termin: item.json.terminDatumFormatiert,
  zeit: item.json.terminZeitFormatiert,
  typ: item.json.erinnerungsTyp,
  status: 'gesendet'
};

return [{ json: logEntry }];
